choose x from {2, 3, 4}
if x MOD 2 = 0 then
  success
else
  failure

// Two successful choices: x=2 and x=4 => ends in SUCCESS

choose x from {1, 2, 3}
choose y from {5, 6}
if (x + y) MOD 5 = 0 then
  success
else
  failure

// 3 * 2 = 6 execution paths, none successful => ends in FAILURE

#include <random>
int D() {
  static std::random_device rd;
  static std::mt19937 gen(rd());
  static std::uniform_int_distribution<int> dist(1, 6);
  return dist(gen);
}

function QUICKSORT(A, p, r)
  if p < r then
    q <- PARTITION(A, p, r)
    QUICKSORT(A, p, q - 1)
    QUICKSORT(A, q + 1, r)

// Initial call: QUICKSORT(A, 1, A.length)

function RANDOMIZED-PARTITION(A, p, r)
  i <- RANDOM(p, r)
  Swap A[r] and A[i]
  return PARTITION(A, p, r)

function RANDOMIZED-QUICKSORT(A, p, r)
  if p < r then
    q <- RANDOMIZED-PARTITION(A, p, r)
    RANDOMIZED-QUICKSORT(A, p, q - 1)
    RANDOMIZED-QUICKSORT(A, q + 1, r)

